package com.aviation.charts.tests;

import org.testng.Assert;
import org.testng.annotations.*;
import com.aviation.charts.pages.ChartViewPage;
import com.aviation.charts.helpers.WaitHelper;
import com.aviation.charts.helpers.AuthHelper;

/**
 * Chart rendering verification tests.
 * Validates ARINC 424 waypoint display and load performance.
 */
public class ChartRenderingTest extends BaseTest {

    private ChartViewPage chartPage;
    private static final int CHART_LOAD_TIMEOUT_MS = 3000;

    @BeforeMethod
    public void setUp() {
        AuthHelper.loginAsTestPilot(driver);
        chartPage = new ChartViewPage(driver);
    }

    @Test(description = "Chart should load within SLA threshold")
    public void chartShouldLoadWithinThreshold() {
        long startTime = System.currentTimeMillis();
        chartPage.navigateToChart("KLAX-ILS28L");
        WaitHelper.waitForChartVisible(driver);
        long loadTime = System.currentTimeMillis() - startTime;

        Assert.assertTrue(
            loadTime <= CHART_LOAD_TIMEOUT_MS,
            String.format("Chart loaded in %dms, expected <= %dms", loadTime, CHART_LOAD_TIMEOUT_MS)
        );
    }

    @Test(
        description = "Chart should display correct ARINC 424 waypoints",
        dataProvider = "waypointData"
    )
    public void chartShouldDisplayCorrectWaypoints(String chartId, String[] expectedWaypoints) {
        chartPage.navigateToChart(chartId);
        WaitHelper.waitForChartVisible(driver);

        for (String waypoint : expectedWaypoints) {
            Assert.assertTrue(
                chartPage.isWaypointDisplayed(waypoint),
                "Expected waypoint not displayed: " + waypoint
            );
        }
    }

    @DataProvider(name = "waypointData")
    public Object[][] waypointData() {
        return new Object[][] {
            { "KLAX-ILS28L", new String[]{ "MINSY", "GADDO", "LUVYN" } },
            { "KSFO-ILS28R", new String[]{ "ARCHI", "MOLEN", "NRRLI" } }
        };
    }

    @AfterMethod
    public void tearDown() {
        chartPage.clearCache();
    }
}
